import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import axios from 'axios';

function ImageAnalyzer() {
  const [selectedImage, setSelectedImage] = useState(null);
  const [preview, setPreview] = useState(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [results, setResults] = useState(null);
  const navigate = useNavigate();

  const handleImageSelect = (e) => {
    const file = e.target.files?.[0];
    if (file) {
      setSelectedImage(file);
      const reader = new FileReader();
      reader.onload = (event) => {
        setPreview(event.target?.result);
      };
      reader.readAsDataURL(file);
      setError('');
      setResults(null);
    }
  };

  const handleAnalyze = async () => {
    if (!selectedImage) {
      setError('Please select an image first');
      return;
    }

    setLoading(true);
    setError('');
    setResults(null);

    try {
      compressImage(selectedImage, async (compressedBase64) => {
        const response = await axios.post('/api/ai/analyze-image', {
          image: compressedBase64,
          imageType: 'image/jpeg'
        });

        const productsResponse = await axios.get('/api/products');
        const allProducts = productsResponse.data;

        const keywords = response.data.keywords || [];
        const matchingProducts = allProducts.filter(product => {
          const productName = product.name.toLowerCase();
          const productCategory = (product.category || '').toLowerCase();

          return keywords.some(keyword => {
            const kw = keyword.toLowerCase();
            return productName.includes(kw) || productCategory.includes(kw);
          });
        });

        setResults({
          analysis: response.data.analysis,
          keywords: keywords,
          fabric: response.data.fabric,
          item: response.data.item,
          products: matchingProducts.slice(0, 9)
        });

        setLoading(false);
      });
    } catch (err) {
      setError(err.response?.data?.message || 'Failed to analyze image');
      console.error('Error:', err);
      setLoading(false);
    }
  };

  const compressImage = (file, callback) => {
    const reader = new FileReader();
    reader.readAsDataURL(file);
    reader.onload = (event) => {
      const img = new Image();
      img.src = event.target.result;
      img.onload = () => {
        const canvas = document.createElement('canvas');
        let width = img.width;
        let height = img.height;

        const maxDim = 2048;
        if (width > height) {
          if (width > maxDim) {
            height = Math.round((height * maxDim) / width);
            width = maxDim;
          }
        } else {
          if (height > maxDim) {
            width = Math.round((width * maxDim) / height);
            height = maxDim;
          }
        }

        canvas.width = width;
        canvas.height = height;

        const ctx = canvas.getContext('2d');
        ctx.drawImage(img, 0, 0, width, height);

        const compressedBase64 = canvas.toDataURL('image/jpeg', 0.85).split(',')[1];
        callback(compressedBase64);
      };
    };
  };

  const handleClear = () => {
    setSelectedImage(null);
    setPreview(null);
    setResults(null);
    setError('');
  };

  return (
    <div style={{ minHeight: '100vh', backgroundColor: '#fff', paddingBottom: '50px' }}>
      {/* Header */}
      <div style={{
        padding: '60px 50px',
        textAlign: 'center',
        borderBottom: '1px solid #f0f0f0'
      }}>
        <h1 style={{
          fontSize: '28px',
          fontWeight: '300',
          letterSpacing: '1px',
          color: '#000',
          margin: '0 0 15px 0',
          textTransform: 'uppercase'
        }}>
          AI FINDER
        </h1>
        <p style={{
          fontSize: '13px',
          color: '#999',
          margin: '0',
          maxWidth: '500px',
          marginLeft: 'auto',
          marginRight: 'auto',
          lineHeight: '1.8'
        }}>
          Upload a fashion photo and discover matching products from our collection
        </p>
      </div>

      {/* Main Container - Sidebar + Content */}
      <div style={{
        display: 'grid',
        gridTemplateColumns: '220px 1fr',
        gap: '0',
        padding: '50px 50px'
      }}>
        {/* Left Sidebar */}
        <div style={{ paddingRight: '40px' }}>
          <h2 style={{
            fontSize: '11px',
            fontWeight: '600',
            letterSpacing: '0.8px',
            color: '#000',
            margin: '0 0 30px 0',
            textTransform: 'uppercase'
          }}>
            UPLOAD PHOTO
          </h2>

          <div
            onDragOver={(e) => e.preventDefault()}
            onDrop={(e) => {
              e.preventDefault();
              const file = e.dataTransfer.files[0];
              if (file) {
                const event = { target: { files: [file] } };
                handleImageSelect(event);
              }
            }}
            style={{
              border: '1px solid #e0e0e0',
              borderRadius: '0px',
              padding: '35px 25px',
              textAlign: 'center',
              cursor: 'pointer',
              transition: 'all 0.3s',
              backgroundColor: '#fafafa',
              marginBottom: '30px'
            }}
            onMouseEnter={(e) => {
              e.currentTarget.style.backgroundColor = '#f5f5f5';
            }}
            onMouseLeave={(e) => {
              e.currentTarget.style.backgroundColor = '#fafafa';
            }}
          >
            <input
              type="file"
              accept="image/*"
              onChange={handleImageSelect}
              style={{ display: 'none' }}
              id="image-input"
            />

            <label htmlFor="image-input" style={{ cursor: 'pointer', display: 'block' }}>
              {preview ? (
                <div>
                  <img
                    src={preview}
                    alt="Preview"
                    style={{
                      maxWidth: '100%',
                      maxHeight: '150px',
                      marginBottom: '12px'
                    }}
                  />
                  <p style={{ fontSize: '11px', color: '#999', margin: '5px 0' }}>
                    Click to change
                  </p>
                </div>
              ) : (
                <div>
                  <div style={{ fontSize: '28px', marginBottom: '12px' }}>📸</div>
                  <p style={{
                    fontSize: '11px',
                    color: '#000',
                    margin: '0 0 4px 0',
                    fontWeight: '500'
                  }}>
                    Click to upload
                  </p>
                </div>
              )}
            </label>
          </div>

          {selectedImage && (
            <div style={{ display: 'flex', gap: '10px', flexDirection: 'column' }}>
              <button
                onClick={handleAnalyze}
                disabled={loading}
                style={{
                  padding: '11px 14px',
                  backgroundColor: loading ? '#ccc' : '#000',
                  color: '#fff',
                  border: 'none',
                  fontSize: '10px',
                  fontWeight: '600',
                  letterSpacing: '0.7px',
                  textTransform: 'uppercase',
                  cursor: loading ? 'not-allowed' : 'pointer',
                  transition: 'all 0.2s'
                }}
              >
                {loading ? 'Analyzing...' : 'Analyze'}
              </button>

              <button
                onClick={handleClear}
                style={{
                  padding: '11px 14px',
                  backgroundColor: '#fff',
                  color: '#000',
                  border: '1px solid #000',
                  fontSize: '10px',
                  fontWeight: '600',
                  letterSpacing: '0.7px',
                  textTransform: 'uppercase',
                  cursor: 'pointer',
                  transition: 'all 0.2s'
                }}
                onMouseEnter={(e) => {
                  e.target.style.backgroundColor = '#000';
                  e.target.style.color = '#fff';
                }}
                onMouseLeave={(e) => {
                  e.target.style.backgroundColor = '#fff';
                  e.target.style.color = '#000';
                }}
              >
                Clear
              </button>
            </div>
          )}
        </div>

        {/* Right Content Area */}
        <div>
          {/* Analysis Box */}
          <div style={{ marginBottom: '60px' }}>
            <h2 style={{
              fontSize: '11px',
              fontWeight: '600',
              letterSpacing: '0.8px',
              color: '#000',
              margin: '0 0 30px 0',
              textTransform: 'uppercase'
            }}>
              ANALYSIS
            </h2>

            <div style={{
              backgroundColor: '#f9f9f9',
              padding: '40px 35px',
              border: '1px solid #f0f0f0',
              minHeight: '200px',
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center'
            }}>
              {loading ? (
                <div style={{ textAlign: 'center' }}>
                  <p style={{ fontSize: '12px', color: '#999', margin: '0' }}>Analyzing image...</p>
                </div>
              ) : results ? (
                <div style={{ width: '100%' }}>
                  {(results.item || results.fabric) && (
                    <div style={{ marginBottom: '15px', display: 'flex', gap: '8px', flexWrap: 'wrap' }}>
                      {results.item && (
                        <span style={{
                          display: 'inline-block',
                          backgroundColor: '#000',
                          color: '#fff',
                          padding: '5px 10px',
                          fontSize: '9px',
                          fontWeight: '600',
                          letterSpacing: '0.5px',
                          textTransform: 'uppercase'
                        }}>
                          {results.item}
                        </span>
                      )}
                      {results.fabric && (
                        <span style={{
                          display: 'inline-block',
                          backgroundColor: '#333',
                          color: '#fff',
                          padding: '5px 10px',
                          fontSize: '9px',
                          fontWeight: '600',
                          letterSpacing: '0.5px',
                          textTransform: 'uppercase'
                        }}>
                          {results.fabric}
                        </span>
                      )}
                    </div>
                  )}

                  <p style={{
                    fontSize: '12px',
                    color: '#333',
                    lineHeight: '1.6',
                    margin: '0'
                  }}>
                    {results.analysis}
                  </p>
                </div>
              ) : (
                <p style={{ fontSize: '12px', color: '#999', margin: '0' }}>
                  Upload an image to see analysis
                </p>
              )}

              {error && (
                <div style={{
                  padding: '10px',
                  backgroundColor: '#ffebee',
                  color: '#d32f2f',
                  fontSize: '11px',
                  marginTop: '15px'
                }}>
                  {error}
                </div>
              )}
            </div>
          </div>

          {/* Products Section */}
          {results && (
            <div>
              {results.products.length > 0 && (
                <div>
                  <h2 style={{
                    fontSize: '11px',
                    fontWeight: '600',
                    letterSpacing: '0.8px',
                    color: '#000',
                    margin: '0 0 30px 0',
                    textTransform: 'uppercase'
                  }}>
                    SIMILAR PRODUCTS ({results.products.length})
                  </h2>

                  <div style={{
                    display: 'grid',
                    gridTemplateColumns: 'repeat(3, 1fr)',
                    gap: '0'
                  }}>
                    {results.products.map(product => (
                      <div
                        key={product._id}
                        onClick={() => navigate(`/product/${product._id}`)}
                        style={{
                          borderRight: '1px solid #f0f0f0',
                          borderBottom: '1px solid #f0f0f0',
                          cursor: 'pointer',
                          transition: 'opacity 0.2s'
                        }}
                        onMouseEnter={(e) => e.currentTarget.style.opacity = '0.8'}
                        onMouseLeave={(e) => e.currentTarget.style.opacity = '1'}
                      >
                        <div style={{
                          aspectRatio: '1',
                          backgroundColor: '#f5f5f5',
                          display: 'flex',
                          alignItems: 'center',
                          justifyContent: 'center',
                          overflow: 'hidden'
                        }}>
                          <img
                            src={product.media?.featured || `/products/${product._id}.jpg`}
                            alt={product.name}
                            style={{
                              width: '100%',
                              height: '100%',
                              objectFit: 'cover'
                            }}
                          />
                        </div>

                        <div style={{ padding: '20px' }}>
                          <h4 style={{
                            fontSize: '11px',
                            fontWeight: '600',
                            letterSpacing: '0.5px',
                            color: '#000',
                            margin: '0 0 8px 0',
                            textTransform: 'uppercase'
                          }}>
                            {product.name}
                          </h4>
                          <p style={{
                            fontSize: '12px',
                            fontWeight: '500',
                            color: '#000',
                            margin: '0'
                          }}>
                            ${product.price}
                          </p>
                        </div>
                      </div>
                    ))}
                  </div>
                </div>
              )}

              {results.products.length === 0 && (
                <div style={{
                  padding: '60px 40px',
                  textAlign: 'center',
                  backgroundColor: '#f9f9f9',
                  border: '1px solid #f0f0f0'
                }}>
                  <p style={{ fontSize: '12px', color: '#999', margin: '0' }}>
                    No matching products found
                  </p>
                </div>
              )}
            </div>
          )}
        </div>
      </div>

      <style>{`
        @keyframes pulse {
          0%, 100% { opacity: 1; }
          50% { opacity: 0.5; }
        }
      `}</style>
    </div>
  );
}

export default ImageAnalyzer;
